public static long[] solve(String[] words) {

    int n = words.length;

    if (n == 1) {

        return new long[] {0};

    }

    int m = n - 1;

    long[] lcp_pairs = new long[m];

    for (int j = 0; j < m; j++) {

        lcp_pairs[j] = computeLCP(words[j], words[j + 1]);

    }

    long[] prefix_max = new long[m];

    prefix_max[0] = lcp_pairs[0];

    for (int i = 1; i < m; i++) {

        prefix_max[i] = Math.max(prefix_max[i - 1], lcp_pairs[i]);

    }

    long[] suffix_max = new long[m];

    suffix_max[m - 1] = lcp_pairs[m - 1];

    for (int i = m - 2; i >= 0; i--) {

        suffix_max[i] = Math.max(suffix_max[i + 1], lcp_pairs[i]);

    }

    long[] answer = new long[n];

    for (int i = 0; i < n; i++) {

        if (n - 1 < 2) {

            answer[i] = 0;

            continue;

        }

        long existing_max = 0;

        if (i == 0) {

            if (m >= 2) {

                existing_max = suffix_max[1];

            } else {

                existing_max = 0;

            }

        } else if (i == n - 1) {

            if (m >= 2) {

                existing_max = prefix_max[m - 2];

            } else {

                existing_max = 0;

            }

        } else {

            long left = (i - 2 >= 0) ? prefix_max[i - 2] : 0;

            long right = (i + 1 < m) ? suffix_max[i + 1] : 0;

            existing_max = Math.max(left, right);

        }

        long new_lcp = 0;

        if (i - 1 >= 0 && i + 1 < n) {

            new_lcp = computeLCP(words[i - 1], words[i + 1]);

        }

        answer[i] = Math.max(existing_max, new_lcp);

    }

    return answer;

}

private static long computeLCP(String a, String b) {

    int minLen = Math.min(a.length(), b.length());

    long lcp = 0;

    for (int i = 0; i < minLen; i++) {

        if (a.charAt(i) != b.charAt(i)) {

            break;

        }

        lcp++;

    }

    return lcp;

}

